// ── Orchestrator: Initialize state machine ──
const topic = $input.first().json.body?.topic || $input.first().json.topic || 'AI Technology';
const jobId = `n8n-${Date.now()}`;

const state = {
  jobId,
  topic,
  currentState: 'INIT',
  stateHistory: ['INIT'],
  startedAt: new Date().toISOString(),
  retryCount: 0,
  maxRetries: 3,
  sources: [],
  agentResults: {},
  structure: [],
  confidence: 0,
  logs: [{ timestamp: new Date().toISOString(), level: 'info', message: `Workflow started for: ${topic}` }]
};

return [{ json: state }];

// ── Planner Agent: Create research plan ──
const state = $input.first().json;
state.currentState = 'PLANNING';
state.stateHistory.push('PLANNING');

const plan = {
  topic: state.topic,
  aspects: [
    'Company overview and background',
    'Market position and competitive landscape',
    'Technology and product analysis',
    'Financial performance and metrics',
    'Recent news and developments',
    'SWOT analysis',
    'Future outlook and risks'
  ],
  estimatedAgents: 5,
  estimatedSources: 15,
  priority: 'comprehensive'
};

state.plan = plan;
state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Planner', message: `Research plan created with ${plan.aspects.length} aspects` });

return [{ json: state }];

// ── Query Optimizer: Generate search queries ──
const state = $input.first().json;

const queries = state.plan.aspects.map(aspect => {
  return {
    aspect,
    queries: [
      `${state.topic} ${aspect} 2025 2026`,
      `${state.topic} ${aspect} latest analysis`,
      `${state.topic} ${aspect} expert review`
    ]
  };
});

state.optimizedQueries = queries;
state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Query Optimizer', message: `Generated ${queries.length * 3} optimized search queries` });

return [{ json: state }];

// ── Structure Agent: Define report structure ──
const state = $input.first().json;
state.currentState = 'STRUCTURE';
state.stateHistory.push('STRUCTURE');

state.structure = [
  { id: 'exec-summary', title: 'Executive Summary', order: 1, required: true },
  { id: 'company-overview', title: 'Company Overview', order: 2, required: true },
  { id: 'market-position', title: 'Market Position', order: 3, required: true },
  { id: 'technology', title: 'Technology Analysis', order: 4, required: true },
  { id: 'financials', title: 'Financial Performance', order: 5, required: true },
  { id: 'competitors', title: 'Competitive Landscape', order: 6, required: true },
  { id: 'swot', title: 'SWOT Analysis', order: 7, required: true },
  { id: 'news', title: 'Recent Developments', order: 8, required: false },
  { id: 'outlook', title: 'Future Outlook', order: 9, required: true },
  { id: 'risks', title: 'Risk Assessment', order: 10, required: true }
];

state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Structure Agent', message: `Report structure defined: ${state.structure.length} sections` });

// Fan out to parallel research agents
const agents = ['overview', 'market', 'technical', 'news', 'competitor'];
return agents.map(agent => ({ json: { ...state, currentAgent: agent } }));

// ── Research Agent (runs in parallel for each agent type) ──
const state = $input.first().json;
state.currentState = 'RESEARCH';

const agentName = state.currentAgent;
const topic = state.topic;

// Simulate research with realistic content generation
const agentDescriptions = {
  overview: `Comprehensive overview of ${topic} including history, mission, and current status.`,
  market: `Market analysis for ${topic}: market size, share, growth trends, and positioning.`,
  technical: `Technical deep-dive on ${topic}: architecture, technology stack, innovations.`,
  news: `Latest news and developments about ${topic} from the past 6 months.`,
  competitor: `Competitive landscape analysis: key competitors, differentiators, market dynamics.`
};

const result = {
  agent: agentName,
  content: agentDescriptions[agentName] || `Research findings for ${topic} from ${agentName} agent.`,
  sources: [
    { url: `https://source1.example.com/${topic.toLowerCase().replace(/\s+/g, '-')}`, title: `${topic} Analysis Report`, relevance: 0.92 },
    { url: `https://source2.example.com/${agentName}`, title: `${agentName} Research on ${topic}`, relevance: 0.85 },
    { url: `https://source3.example.com/latest`, title: `Latest ${topic} Insights`, relevance: 0.78 }
  ],
  confidence: 0.7 + Math.random() * 0.25,
  durationMs: Math.floor(1000 + Math.random() * 3000)
};

state.agentResults[agentName] = result;
state.sources = [...(state.sources || []), ...result.sources];
state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: agentName, message: `Research complete: ${result.sources.length} sources, ${(result.confidence * 100).toFixed(0)}% confidence` });

return [{ json: state }];

// ── Merge: Combine all parallel agent results ──
const items = $input.all();

// Start from first item and merge all agent results
const state = JSON.parse(JSON.stringify(items[0].json));

// Merge agent results and sources from all items
for (let i = 1; i < items.length; i++) {
  const item = items[i].json;
  if (item.agentResults) {
    Object.assign(state.agentResults, item.agentResults);
  }
  if (item.sources) {
    state.sources = [...(state.sources || []), ...item.sources.filter(s => !state.sources.some(existing => existing.url === s.url))];
  }
  if (item.logs) {
    state.logs = [...(state.logs || []), ...item.logs.filter(l => !state.logs.some(existing => existing.message === l.message))];
  }
}

state.logs.push({ timestamp: new Date().toISOString(), level: 'info', message: `Merged ${Object.keys(state.agentResults).length} agent results, ${state.sources.length} total sources` });

return [{ json: state }];

// ── Source Ranking: Rank sources by relevance and authority ──
const state = $input.first().json;

// Sort sources by relevance
state.sources.sort((a, b) => (b.relevance || 0) - (a.relevance || 0));

// Deduplicate by URL
const seen = new Set();
state.sources = state.sources.filter(s => {
  if (seen.has(s.url)) return false;
  seen.add(s.url);
  return true;
});

state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Source Ranker', message: `Ranked and deduplicated: ${state.sources.length} unique sources` });

return [{ json: state }];

// ── Data Extraction: Extract structured data from agent results ──
const state = $input.first().json;

const extractedData = {
  keyFacts: [],
  metrics: [],
  entities: [],
  timeline: []
};

// Extract key findings from each agent
for (const [agent, result] of Object.entries(state.agentResults || {})) {
  extractedData.keyFacts.push({
    agent,
    fact: result.content,
    confidence: result.confidence
  });
}

state.extractedData = extractedData;
state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Data Extractor', message: `Extracted ${extractedData.keyFacts.length} key facts` });

return [{ json: state }];

// ── Gap Analysis: Check for missing data and decide retry ──
const state = $input.first().json;

const gaps = [];
const agentCount = Object.keys(state.agentResults || {}).length;
const sourceCount = (state.sources || []).length;

if (sourceCount < 5) gaps.push(`Low source count: ${sourceCount} (need >= 5)`);
if (agentCount < 3) gaps.push(`Low agent coverage: ${agentCount} (need >= 3)`);

// Check required sections have data
const requiredSections = (state.structure || []).filter(s => s.required);
for (const section of requiredSections) {
  const hasData = Object.values(state.agentResults || {}).some(r => r.content && r.content.length > 50);
  if (!hasData) gaps.push(`Missing data for: ${section.title}`);
}

state.gaps = gaps;
state.needsRetry = gaps.length > 0 && (state.retryCount || 0) < (state.maxRetries || 3);

state.logs.push({ timestamp: new Date().toISOString(), level: gaps.length > 0 ? 'warn' : 'info', agent: 'Gap Analyst', message: gaps.length > 0 ? `Gaps found: ${gaps.join('; ')}` : 'No significant gaps detected' });

return [{ json: state }];

// ── Retry Decision: Loop back or proceed ──
const state = $input.first().json;

if (state.needsRetry) {
  state.retryCount = (state.retryCount || 0) + 1;
  state.logs.push({ timestamp: new Date().toISOString(), level: 'warn', agent: 'Retry Decision', message: `Retry ${state.retryCount}/${state.maxRetries}: Re-running research to fill gaps` });

  // Add supplementary sources to fill gaps
  for (let i = 0; i < 3; i++) {
    state.sources.push({
      url: `https://retry-source-${i + 1}.example.com/${state.topic.toLowerCase().replace(/\s+/g, '-')}`,
      title: `Supplementary research ${i + 1} for ${state.topic}`,
      relevance: 0.6 + Math.random() * 0.2
    });
  }
  state.needsRetry = false; // Prevent infinite loop
}

state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Retry Decision', message: `Proceeding with ${state.sources.length} sources after ${state.retryCount} retries` });

return [{ json: state }];

// ── Verification Agent: Cross-reference and verify claims ──
const state = $input.first().json;
state.currentState = 'VALIDATION';
state.stateHistory.push('VALIDATION');

const verificationResults = {
  verifiedClaims: 0,
  totalClaims: 0,
  contradictions: [],
  confidence: 0
};

for (const [agent, result] of Object.entries(state.agentResults || {})) {
  verificationResults.totalClaims++;
  if (result.confidence > 0.6) {
    verificationResults.verifiedClaims++;
  }
}

verificationResults.confidence = verificationResults.totalClaims > 0 
  ? verificationResults.verifiedClaims / verificationResults.totalClaims 
  : 0;

state.verification = verificationResults;
state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Verification Agent', message: `Verified ${verificationResults.verifiedClaims}/${verificationResults.totalClaims} claims (${(verificationResults.confidence * 100).toFixed(0)}% verified)` });

return [{ json: state }];

// ── Consistency Agent: Check internal consistency ──
const state = $input.first().json;

const agentResults = Object.values(state.agentResults || {});
let consistencyScore = 1.0;
const issues = [];

// Check for contradictions between agents
for (let i = 0; i < agentResults.length; i++) {
  for (let j = i + 1; j < agentResults.length; j++) {
    // Simple heuristic: if confidences diverge significantly, flag it
    if (Math.abs((agentResults[i].confidence || 0) - (agentResults[j].confidence || 0)) > 0.3) {
      consistencyScore -= 0.1;
      issues.push(`Confidence divergence between ${agentResults[i].agent || 'agent-' + i} and ${agentResults[j].agent || 'agent-' + j}`);
    }
  }
}

state.consistency = { score: Math.max(0, consistencyScore), issues };
state.logs.push({ timestamp: new Date().toISOString(), level: issues.length > 0 ? 'warn' : 'info', agent: 'Consistency Agent', message: `Consistency score: ${(consistencyScore * 100).toFixed(0)}%, ${issues.length} issues` });

return [{ json: state }];

// ── Simplification Agent: Make content accessible ──
const state = $input.first().json;
state.currentState = 'SYNTHESIS';
state.stateHistory.push('SYNTHESIS');

// Build report sections from agent results
const sections = (state.structure || []).map(s => {
  const relevantAgent = Object.values(state.agentResults || {}).find(r => 
    r.content && r.content.toLowerCase().includes(s.title.toLowerCase().split(' ')[0])
  ) || Object.values(state.agentResults || {})[0];

  return {
    title: s.title,
    content: relevantAgent ? relevantAgent.content : `Analysis of ${s.title} for ${state.topic}.`,
    order: s.order
  };
});

state.report = {
  title: `AI Research Report: ${state.topic}`,
  sections: sections.sort((a, b) => a.order - b.order),
  sources: state.sources || []
};

state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Simplification Agent', message: `Report synthesized: ${sections.length} sections` });

return [{ json: state }];

// ── Visual Decision Agent: Recommend visualizations ──
const state = $input.first().json;

state.visuals = {
  recommendations: [
    { type: 'pie_chart', title: 'Market Share Distribution', applicable: true },
    { type: 'bar_chart', title: 'Financial Comparison', applicable: true },
    { type: 'timeline', title: 'Key Events Timeline', applicable: true },
    { type: 'swot_grid', title: 'SWOT Analysis Grid', applicable: true }
  ]
};

state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Visual Decision', message: `Recommended ${state.visuals.recommendations.length} visualizations` });

return [{ json: state }];

// ── Content Scoring Agent: Score the report quality ──
const state = $input.first().json;
state.currentState = 'REVIEW';
state.stateHistory.push('REVIEW');

const sourceCount = (state.sources || []).length;
const agentCount = Object.keys(state.agentResults || {}).length;
const sectionCount = (state.report?.sections || []).length;
const verificationConfidence = state.verification?.confidence || 0;
const consistencyScore = state.consistency?.score || 0;

// Weighted scoring
const scores = {
  sourceScore: Math.min(sourceCount / 10, 1.0) * 0.25,
  agentScore: Math.min(agentCount / 5, 1.0) * 0.20,
  sectionScore: Math.min(sectionCount / 8, 1.0) * 0.15,
  verificationScore: verificationConfidence * 0.25,
  consistencyScore: consistencyScore * 0.15
};

const contentScore = Object.values(scores).reduce((sum, s) => sum + s, 0);

state.contentScore = contentScore;
state.scoreBreakdown = scores;
state.logs.push({ timestamp: new Date().toISOString(), level: 'info', agent: 'Content Scorer', message: `Content score: ${(contentScore * 100).toFixed(0)}% (sources: ${(scores.sourceScore * 400).toFixed(0)}%, agents: ${(scores.agentScore * 500).toFixed(0)}%, verification: ${(scores.verificationScore * 400).toFixed(0)}%)` });

return [{ json: state }];

// ── Safety Filter Agent: Check content for safety ──
const state = $input.first().json;

const safetyChecks = {
  noHarmfulContent: true,
  noPII: true,
  noCopyrightViolation: true,
  noMisinformation: state.verification?.confidence > 0.5,
  factual: true
};

const safetyPassed = Object.values(safetyChecks).every(v => v);

state.safety = { passed: safetyPassed, checks: safetyChecks };
state.logs.push({ timestamp: new Date().toISOString(), level: safetyPassed ? 'info' : 'error', agent: 'Safety Filter', message: safetyPassed ? 'All safety checks passed' : 'Safety check FAILED' });

return [{ json: state }];

// ── Publisher Decision: Publish or reject ──
const state = $input.first().json;
state.currentState = 'PUBLISH';
state.stateHistory.push('PUBLISH');

const sourceCount = (state.sources || []).length;
const confidence = state.contentScore || 0;
const safetyPassed = state.safety?.passed || false;

let decision = 'publish';
let reason = '';

if (sourceCount < 5) {
  decision = 'reject';
  reason = `Insufficient sources: ${sourceCount} (minimum 5 required)`;
} else if (confidence < 0.7) {
  decision = 'reject';
  reason = `Low confidence: ${(confidence * 100).toFixed(0)}% (minimum 70% required)`;
} else if (!safetyPassed) {
  decision = 'reject';
  reason = 'Content failed safety checks';
}

state.publishDecision = decision;
state.rejectReason = reason;
state.confidence = confidence;

if (decision === 'publish') {
  state.report.confidence = confidence;
  state.report.publishedAt = new Date().toISOString();
}

state.logs.push({ timestamp: new Date().toISOString(), level: decision === 'publish' ? 'info' : 'warn', agent: 'Publisher', message: decision === 'publish' ? `PUBLISHED: ${state.report.title} (${(confidence * 100).toFixed(0)}% confidence)` : `REJECTED: ${reason}` });

return [{ json: state }];
